'use server';

import { headers } from 'next/headers';
import { initializeApp, getApps, App } from 'firebase-admin/app';
import { getAuth } from 'firebase-admin/auth';
import { firebaseConfig } from '@/firebase/config';

// This function will run on the server when the app loads.
// It's a temporary measure to grant admin privileges.

// Initialize Firebase Admin SDK if not already initialized
let adminApp: App;
if (!getApps().length) {
  adminApp = initializeApp({
    projectId: firebaseConfig.projectId,
  });
} else {
  adminApp = getApps()[0];
}

const adminAuth = getAuth(adminApp);

export async function setAdminClaimForUser(uid: string, email: string | null) {
  // IMPORTANT: This is hardcoded for security.
  const targetEmail = 'stakithire@gmail.com';

  if (email === targetEmail) {
    try {
      const user = await adminAuth.getUser(uid);
      // Check if the admin claim is already set to avoid unnecessary writes
      if (user.customClaims?.['admin'] !== true) {
        await adminAuth.setCustomUserClaims(uid, { admin: true });
        console.log(`Admin claim has been set for ${email}.`);
        // We need to tell the client to refresh the token
        return { claimSet: true };
      }
    } catch (error) {
      console.error('Error setting admin claim:', error);
      return { claimSet: false, error: 'Failed to set claim.' };
    }
  }
  return { claimSet: false };
}
